	tst_status_type_cd varchar(20) ,
	status_cd varchar(20) ,
	note varchar(2000),
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE wldtaxon_statuses IS 'The status of a taxon.';
COMMENT ON COLUMN wldtaxon_statuses.note IS 'Text about StatusCod';
COMMENT ON COLUMN wldtaxon_statuses.status_cd IS 'Code for a  wildlife status. Ex:RED, BLUE, YELLOW, EXTINCT';
COMMENT ON COLUMN wldtaxon_statuses.tst_status_type_cd IS 'FK: StatusTypes Code identifying type ofstatus';
COMMENT ON COLUMN wldtaxon_statuses.when_created IS 'When was this record created. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_statuses.when_updated IS 'When was this record last updated.Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_statuses.who_created IS 'Who created this record. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_statuses.who_updated IS 'Who last updated this record.Used by Warehouse processes.';
