ALTER TABLE wldtaxon_statuses ADD PRIMARY KEY (tst_status_type_cd,status_cd);

CREATE TABLE wldtaxon_status_types (
	status_type_cd varchar(20) ,
	name varchar(50) ,
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE wldtaxon_status_types IS 'The type of Taxon status as defined by the monitoring body.';
