COMMENT ON COLUMN wldtaxon_status_types.who_created IS 'Who created this record. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_status_types.who_updated IS 'Who last updated this record.Used by Warehouse processes.';
ALTER TABLE wldtaxon_status_types ADD PRIMARY KEY (status_type_cd);

CREATE TABLE wldtaxon_syns (
	txn_id bigint ,
	txn_id_an_old_name_for bigint ,
	start_date timestamp ,
	end_date timestamp,
	reason varchar(20),
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE wldtaxon_syns IS 'A relationship between an accepted taxonomic name and a predecessor to it. Used to record the former record(s) used to identify a taxon. Allows queries on observations of a taxon to include observations made on a former name for that taxon.';
COMMENT ON COLUMN wldtaxon_syns.end_date IS 'Date on which the synonym ceases to be valid';
COMMENT ON COLUMN wldtaxon_syns.reason IS 'Reason for creating the synonym, eg. "split"';
COMMENT ON COLUMN wldtaxon_syns.start_date IS 'The date a new name was identified or recorded.';
COMMENT ON COLUMN wldtaxon_syns.txn_id IS 'FK: TaxonmicUnit The Taxon that has a synonym.';
COMMENT ON COLUMN wldtaxon_syns.txn_id_an_old_name_for IS 'FK: TaxonomicUnit. The taxon that is a synonym.';
COMMENT ON COLUMN wldtaxon_syns.when_created IS 'When was this record created. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_syns.when_updated IS 'When was this record last updated.Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_syns.who_created IS 'Who created this record. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_syns.who_updated IS 'Who last updated this record.Used by Warehouse processes.';
CREATE INDEX wld_tsn_txn_id ON wldtaxon_syns (txn_id);
CREATE INDEX wld_tsn_txn_id_old_name ON wldtaxon_syns (txn_id_an_old_name_for);
ALTER TABLE wldtaxon_syns ADD PRIMARY KEY (txn_id,txn_id_an_old_name_for);

CREATE TABLE wldtaxon_types (
	kingdom varchar(10) ,
	name varchar(20) ,
	hierarchy_level smallint ,
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE wldtaxon_types IS 'Levels in the taxonomic classification hierarchy for each Kingdom. Ex. Phylum, Class, Order, Family, Genus, Species, Subspecies.';
COMMENT ON COLUMN wldtaxon_types.hierarchy_level IS 'A number indicating the sequence of this taxon type in the hierar';
COMMENT ON COLUMN wldtaxon_types.kingdom IS 'The kingdom the taxon hierarchy represents';
COMMENT ON COLUMN wldtaxon_types.name IS 'The name of the taxon level, eg. PHYLUM, ORDER, GENUS, etc';
COMMENT ON COLUMN wldtaxon_types.when_created IS 'When was this record created. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_types.when_updated IS 'When was this record last updated.Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_types.who_created IS 'Who created this record. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_types.who_updated IS 'Who last updated this record.Used by Warehouse processes.';
ALTER TABLE wldtaxon_types ADD PRIMARY KEY (kingdom,name);

