	tst_status_type_cd varchar(20) ,
	txn_id bigint ,
	start_date timestamp ,
	end_date timestamp,
	qualifier_code varchar(10),
	txs_status_cd varchar(20) ,
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE wldtaxon_unit_status IS 'The status of taxonomic unit for a taxon status type for a period of time.';
COMMENT ON COLUMN wldtaxon_unit_status.end_date IS 'The date that a classification of an organism became invalid.';
COMMENT ON COLUMN wldtaxon_unit_status.qualifier_code IS 'A code that qualifies a TaxonStatus.';
COMMENT ON COLUMN wldtaxon_unit_status.start_date IS 'The date that a classification became valid or was recorded';
COMMENT ON COLUMN wldtaxon_unit_status.tst_status_type_cd IS 'FK: StatusTypes Code for a StatusTyp';
COMMENT ON COLUMN wldtaxon_unit_status.txn_id IS 'FK: TaxonomicUnit';
COMMENT ON COLUMN wldtaxon_unit_status.txs_status_cd IS 'FK: TaxonStatus Code for the status of the taxon';
COMMENT ON COLUMN wldtaxon_unit_status.when_created IS 'When was this record created. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_unit_status.when_updated IS 'When was this record last updated.Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_unit_status.who_created IS 'Who created this record. Used by Warehouse processes.';
COMMENT ON COLUMN wldtaxon_unit_status.who_updated IS 'Who last updated this record.Used by Warehouse processes.';
CREATE INDEX wld_txnunst_status_cd ON wldtaxon_unit_status (txs_status_cd);
CREATE INDEX wld_txnunst_txn_id ON wldtaxon_unit_status (txn_id);
ALTER TABLE wldtaxon_unit_status ADD PRIMARY KEY (tst_status_type_cd,txn_id,txs_status_cd);

CREATE TABLE wld_common_names (
	id bigint ,
	name varchar(50) ,
	name_level numeric(38) ,
	parent_id bigint,
	who_created varchar(30) ,
	when_created timestamp ,
	who_updated varchar(30),
	when_updated timestamp
) ;
COMMENT ON TABLE wld_common_names IS 'A hierarchical index of common names. Ex: Birds is the parent of Loons, Phalaropes and Thrushes.';
COMMENT ON COLUMN wld_common_names.id IS 'PK System generated unique identifier.';
COMMENT ON COLUMN wld_common_names.name IS 'The name of the common name index.';
COMMENT ON COLUMN wld_common_names.name_level IS 'The level of the name in the common name index hierarchy.';
COMMENT ON COLUMN wld_common_names.parent_id IS 'FK: CommonName The parent in the common name hierarchy.';
COMMENT ON COLUMN wld_common_names.when_created IS 'When was this record created. Used by Warehouse processes.';
COMMENT ON COLUMN wld_common_names.when_updated IS 'When was this record last updated.Used by Warehouse processes.';
COMMENT ON COLUMN wld_common_names.who_created IS 'Who created this record. Used by Warehouse processes.';
COMMENT ON COLUMN wld_common_names.who_updated IS 'Who last updated this record.Used by Warehouse processes.';
CREATE INDEX wld_tcn_parent_id ON wld_common_names (parent_id);
ALTER TABLE wld_common_names ADD PRIMARY KEY (id);
ALTER TABLE wld_common_names ADD UNIQUE (name);

